import os
from google.cloud import storage
from google.cloud import firestore
from google.pubsub import pubsub

def process_file(event, context):
    bucket_name = event['bucket']
    file_name = event['name']

    # Initialize Cloud Storage client
    storage_client = storage.Client()
    bucket = storage_client.get_bucket(bucket_name)
    blob = bucket.blob(file_name)

    # Read file content from Google Cloud Storage
    data = blob.download_as_text()

    # Initialize Firestore client
    db = firestore.Client()
    doc_ref = db.collection(u'your-collection').document(u'your-document-id')
    doc_ref.set({
        u'data': data
    })

    # Initialize Pub/Sub client
    pubsub_client = pubsub.PublisherClient()
    topic_path = pubsub_client.topic_path('your-project-id', 'your-topic-name')
    data_msg = pubsub.types.PublishRequest(topic=topic_path, data=data.encode('utf-8'))
    pubsub_client.publish(data_msg)